import{_ as t,o,c as a,ak as i}from"./chunks/framework.Dpc0wyhY.js";const p=JSON.parse('{"title":"Flows","description":"","frontmatter":{},"headers":[],"relativePath":"automation/flows.md","filePath":"automation/flows.md"}'),n={name:"automation/flows.md"};function r(s,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="flows" tabindex="-1">Flows <a class="header-anchor" href="#flows" aria-label="Permalink to “Flows”">​</a></h1><p>Flows enable custom, event-driven data processing and task automation. Each flow is composed of one trigger, a series of operations, and a data chain that is passed between each step.</p><h2 id="fields" tabindex="-1">Fields <a class="header-anchor" href="#fields" aria-label="Permalink to “Fields”">​</a></h2><ul><li><strong>Name (required)</strong> — The displayed name of the Flow.</li><li><strong>Status</strong> — Sets the flow to active or inactive.</li><li><strong>Icon</strong> — Adds an icon to help quickly identify the flow.</li><li><strong>Description</strong> — Sets a brief verbal description of the flow.</li><li><strong>Color</strong> — Sets a color to help identify the flow.</li><li><strong>Activity and Logs Tracking</strong> — Selects whether the flow should be tracked in both the activity log and the flow&#39;s logs, only in the activity log, or neither.</li></ul><h2 id="logs" tabindex="-1">Logs <a class="header-anchor" href="#logs" aria-label="Permalink to “Logs”">​</a></h2><p>Accessible from the sidebar, logs store information for each flow execution. Each log will display information from triggers as well as each operation in the flow.</p><p>Logs are not a 1:1 mapping to the data chain. Each trigger and operation gets its own dropdown, which stores its relevant data. Here&#39;s what you&#39;ll get from each of these:</p><h3 id="trigger" tabindex="-1">Trigger <a class="header-anchor" href="#trigger" aria-label="Permalink to “Trigger”">​</a></h3><ul><li><strong>Options</strong> — The values you input when you configured the trigger.</li><li><strong>Payload</strong> — Displays the data appended under <code>$trigger</code>, which includes the data passed into the flow itself.</li><li><strong>Accountability</strong> — Displays data appended under <code>$accountability</code>, which is a breakdown of the permissions and request information of the user that triggered that event.</li></ul><p>Note that <code>$accountability</code> is not nested under the <code>$trigger</code> key. However, it is listed under the trigger in the log because <code>$accountability</code> is generated by the trigger.</p><h3 id="operationkey" tabindex="-1"><code>&lt;OperationKey&gt;</code> <a class="header-anchor" href="#operationkey" aria-label="Permalink to “&lt;OperationKey&gt;”">​</a></h3><ul><li><strong>Options</strong> — The values you input when you configured the operation. <em>(These configuration options are not stored on the data chain)</em>.</li><li><strong>Payload</strong> — Displays the data appended under this <code>&lt;operationKey&gt;</code>.</li></ul><blockquote><p><strong>Warning: Logs are stored in the database</strong> Flows configured to track will store this information in the database, which may require occasionally deleting.</p></blockquote><blockquote><p><strong>Where is <code>$last</code>?</strong><code>$last</code> constantly updates to store the data of the most recently executed operation. Since the log shows the results of the entire flow, <code>$last</code> would only be the final operation in the flow.</p></blockquote><p><em>Video documentation available in the admin panel.</em></p>',15)])])}const f=t(n,[["render",r]]);export{p as __pageData,f as default};
